MAGIC = b"GSV1"
TYPE_STATUS_QUERY = 0x01
TYPE_STATUS_RESPONSE = 0x81
TYPE_FRAGMENT = 0x90
TYPE_ACK = 0x91
TYPE_ERROR = 0xFF

FLAG_COMPRESSED = 0x01

DEFAULT_MTU = 1200
FRAG_HEADER_FMT = "!4sBBBBIHHHHH"  # magic, type, flags, reserved, version, msg_id, total_frags, frag_index, frag_size, payload_len, checksum16
FRAG_HEADER_SIZE = struct.calcsize(FRAG_HEADER_FMT)

RESP_HEADER_FMT = "!4sBBBIH"  # magic, type, flags, version, msg_id, payload_len
RESP_HEADER_SIZE = struct.calcsize(RESP_HEADER_FMT)

QUERY_HEADER_FMT = "!4sBBBIH"  # magic, type, flags, version, msg_id, payload_len
QUERY_HEADER_SIZE = struct.calcsize(QUERY_HEADER_FMT)

ACK_FMT = "!4sBBBIH"  # magic, type, flags, version, msg_id, payload_len(=0)
ACK_SIZE = struct.calcsize(ACK_FMT)

VERSION = 1

def crc16(data: bytes) -> int:
    # Use zlib crc32 truncated as a pragmatic integrity check.
    return zlib.crc32(data) & 0xFFFF

def now_ms() -> int:
    return int(time.time() * 1000)

def rand_str(n: int) -> str:
    return "".join(random.choice(string.ascii_letters + string.digits) for _ in range(n))

